CREATE TABLE `contract_attachment` (
  `attachment_id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT 'attachment id',
  `contract_id` bigint unsigned DEFAULT NULL COMMENT 'contract id',
  `file_id` bigint unsigned NOT NULL COMMENT 'file id',
  `ocr_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL DEFAULT 'PENDING' COMMENT 'ocr status',
  `ocr_text` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin COMMENT 'ocr text',
  `ocr_error` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'ocr error',
  `page_count` int unsigned DEFAULT NULL COMMENT 'page count',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'created time',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'updated time',
  `is_deleted` tinyint unsigned NOT NULL DEFAULT '0' COMMENT 'delete flag',
  PRIMARY KEY (`attachment_id`),
  KEY `idx_contract_id` (`contract_id`),
  KEY `idx_file_id` (`file_id`),
  KEY `idx_ocr_status` (`ocr_status`)
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin COMMENT='contract attachment';
/*!40101 SET character_set_client = @saved_cs_client */;

