/*!40000 ALTER TABLE `contract_attachment` DISABLE KEYS */;
INSERT INTO `contract_attachment` VALUES (1,1001,4,'SUCCESS','设备采购合同扫描件文本摘要。',NULL,3,'2026-06-03 11:44:38','2026-06-03 11:44:38',0),(2,1003,5,'SUCCESS','软件系统销售合同扫描件文本摘要。',NULL,5,'2026-06-03 11:44:38','2026-06-03 11:44:38',0),(10,NULL,45,'SUCCESS','<h1>合同编号：</h1><p>技术开发（委托）与技术服务合同</p><p>项目名称：</p><p>委托方（甲方）：</p><p>受托方（乙方）：</p><p>签订时间：</p><p>签订地点：</p><p>填  写  说  明</p><h3>一、本合同为中华人民共和国科学部印制的技术开发（委托）合</h3><p>同示范文本，各技术合同登记机构可推介技术合同当事人参照使用。</p><h3>二、本合同书适用于一方当事人委托另一方当事人进行新技术、</h3><p>新产品、新工艺、新材料或者新品种及其系统的研究开发所订立的技</p><p>术开发合同。</p><h3>三、签约一方为多个当事人的，可按各自在合同关系中的作用等，</h3><p>在“委托方”、“受托方”项下（增页）分别排列为共同委托人或共同</p><p>受托人。</p><h3>四、本合同书未尽事项，可由当事人附页另行约定，并可作为本</h3><p>合同的组成部分。</p><h3>五、当事人使用本合同书时约定无需填写的条款，应在该条款处</h3><p>注明“无“等字样。</p><p>技术开发（委托）与技术服务合同</p><p>委托方（甲方）：</p><p>住  所  地：</p><p>法定代表人：</p><p>项目联系人：</p><p>联系方式：     电话</p><p>通讯地址：</p><p>电  话：                            传  真：</p><p>电子信箱：</p><p>受托方（乙方）：</p><p>住  所  地：</p><p>法定代表人：</p><p>项目联系人：</p><p>联系方式：</p><p>通讯地址：</p><p>电  话：                      传  真：</p><p>电子信箱：</p><p>本合同甲方委托乙方研究开发        项目线上技术平台及后</p><p>续为该线上平台提供技术服务包括软件持续开发升级、技术改造、平</p><p>台运营维护等等，并支付研究开发、技术服务等经费和报酬，乙方接</p><p>受委托并进行此项研究开发工作。双方经过平等协商，在真实、充分</p><p>地表达各自意愿的基础上，根据《中华人民共和国民法典》的规定，</p><p>达成如下协议，并由双方共同恪守。</p><h2>第一条 本合同研究开发项目的要求如下：</h2><p>1．技术目标：</p><p>。</p><h2>第二条  乙方应在本合同生效后       日内向甲方提交研究开</h2><p>发计划。研究开发计划应包括以下主要内容：</p><p>1．                                                   ；</p><p>2．                                                    ；</p><p>3．                                                    ；</p><h2>第三条  乙方应按下列进度完成研究开发工作：</h2><p>1．                      ；</p><p>2．                       ；</p><p>3．                                                  ；</p><p>4．                                                  。</p><h2>第四条 甲方应向乙方提供的技术资料及协作事项如下：</h2><p>1．技术资料清单：                            。</p><p>2．提供时间和方式：</p><p>。</p><p>3．其他协作事项：    提供系统运行环境、指派项目协调人负</p><p>责系统的交互确认工作。</p><p>4．本合同履行完毕后，上述技术资料按以下方式处理：</p><p>由         。</p><h2>第五条 甲方应按以下方式支付研究开发经费和报酬：</h2><p>1．研究开发经费由甲方        （一次或分期）支付乙方。具</p><p>体支付方式和时间如下：</p><p>（1）    元 为签定合同后  日内支付</p><p>（2）    元 为系统开发结束后  日内支付</p><p>乙方开户银行名称、地址和帐号为：</p><p>开户银行：</p><p>地址：</p><p>帐号：</p><h2>第七条  本合同的变更必须由双方协商一致，并以书面形式确</h2><p>定。但有下列情形之一的，一方可以向另一方提出变更合同权利与义</p><p>务的请求，另一方应当在        日内予以答复；逾期未予答复的，</p><p>视为同意。</p><p>1．        无                                        ；</p><p>2．                                                ；</p><p>3．                                                ；</p><p>4．                                                。</p><h2>第八条  未经甲方同意，乙方不得将本合同项目部分或全部研究</h2><p>开发工作转让第三人承担。但有下列情况之一的，乙方可以不经甲方</p><p>同意，将本合同项目部分或全部研究开发工作转让第三人承但：</p><p>1．                                                   ；</p><p>2．                                                   ；</p><p>3．                                                  ；</p><p>4．                                                  。</p><h2>第九条  在本合同履行中，因出现在现有技术水平和条件下维难</h2><p>以克服的技术困难，导致研究开发失败或部分失败，并造成一方或双</p><p>方损失的，双方按如下约定承担风险损失：   无。</p><p>双方确定，本合同项目的技术风险按  无</p><p>的方式认定。认</p><p>定技术风险的基本内容应当包括技术风险的存在、范围、程度及损失</p><p>大小等。认定技术风险的基本条件是：</p><p>1．本合同项目在现有技术水平条件下具有足够的难度；</p><p>2．乙方在主观上无过错且经认定研究开发失败为合理的失败。</p><p>一方发现技术风险存在并有可能致使研究开发失败或部分失败的情</p><p>形时，应当在        日内通知另一方并采取适当措施减少损失。逾</p><p>期未通知并未采取适当措施而致使损失扩大的，应当就扩大的损失承</p><p>担赔偿责任。</p><h2>第十一条  双方确定因履行本合同应遵守的保密义务如下：</h2><p>甲方：</p><p>1． 保密内容（包括技术信息和经营信息）：            ；</p><p>2． 涉密人员范围：            ；</p><p>3． 保密期限：         ；</p><p>4． 泄密责任：</p><p>乙方：</p><p>1．保密内容（包括技术信息和经营信息）：                ；</p><p>2．涉密人员范围：           ；</p><p>3．保密期限：        ；</p><p>4．泄密责任：                    。</p><h2>第十二条  乙方应当按以下方式向甲方交付研究开发成果：</h2><p>1．研究开发成果交付的形式及数量：</p><h2>第十三条  双方确定，按以下标准及方法对乙方完成的研究开发</h2><p>成果进行险收：               。</p><h2>第十四条  乙方应当保证其交付给甲方的研究开发成果不侵犯</h2><p>任何第三人的合法权益。如发生第三人指控甲方实施的技术侵权的，</p><p>乙方应当                     。</p><h2>第十五条  双方确定，因履行本合同所产生的研究开发成果及其</h2><p>相关知识产权权利归属，按下列第      种方式处理：</p><p>1．               方享有申请专利的权利。</p><p>专利权取得后的使用和有关利益分配方式如下：     。</p><p>2．按技术秘密方式处理。有关使用和转让的权利归属及由此产</p><p>生的利益按以下约定处理：</p><p>（1）技术秘密的使用权：</p><p>（2）技术秘密的转让权：</p><p>（3）相关利益的分配办法：</p><p>双方对本合同有关的知识产权权利归属特别约定如下：</p><h2>第十六条  乙方不得在向甲方交付研究开发成果之前，自行将研</h2><p>究开发成果转让给第三人。</p><h2>第十七条  乙方完成本合同项目的研究开发人员享有在有关技</h2><p>术成果文件上写明技术成果完成者的权利和取得有关荣誉证书、奖励</p><p>的权利。</p><h2>第十八条  乙方利用研究开发经费所购置与研究开发工作有关</h2><p>的设备、器材、资料等财产，归            方所有。</p><p>双方确定，乙方应在向甲方交付研究开发成果后，根据甲方的请</p><p>求，为甲方指定的人员提供技术指导和培训，或提供与使用该研究开</p><p>发成果相关的技术服务。</p><p>1．技术服务和指导内容：                  。</p><p>2．地点和方式：                   。</p><p>3．费用及支付方式：             。</p><h2>第二十条  双方确定：任何一方违反本合同约定，造成研究开发</h2><p>工作停滞、延误或失败的，按以下约定承担违约责任：</p><p>1．          方违反本合同第       条约定，应当  按合同额</p><p>的 5%赔偿                                （支付违约金或损失</p><p>赔偿额的计算方法）。</p><p>2．          方违反本合同第       条约定，应当 按合同额</p><p>的 5%赔偿                     （支付违约金或损失赔偿额的计算</p><p>方法）。</p><h2>第二十一条  双方确定，甲方有权利用乙方按照本合同约定提供</h2><p>的研究开发成果，进行后继改进。由此产生的具有实质性或创造性技</p><p>术进步特征的新的技术成果及其权利归属，由        方享有。</p><p>乙方有权在完成本合同约定的研究开发工作后，利用该项目研究</p><p>开发成果进行后续改进。由此产生的具有实质性或创造性技术进步特</p><p>征的新的技术成果，归           享有。具体相关利益的分配办法</p><p>如下：              。</p><h2>第二十二条  双方确定，在本合同有效期内，甲方指定</h2><p>为甲方项目联系人，乙方指定                为乙方项目联系人。</p><p>项目联系人承担以下责任：</p><p>1．</p><p>2．</p><p>3．</p><p>一方变更项目联系人的，应当及时以书面形式通知另一方。未及</p><p>时通知并影响本合同履行或造成损失的，应承担相应的责任。</p><h2>第二十三条  双方确定，出现下列情形，致使本合同的履行成为</h2><p>不必要或不可能的，一方可以通知另一方解除本合同；</p><p>1．因发生不可抗力或技术风险；</p><p>2．</p><p>3．</p><h2>第二十四条  双方因履行本合同而发生的争议，应协商、调解解</h2><p>决。协商、调解不成的，确定按以下第          种方式处理：</p><p>1．提交                                仲裁委员会仲裁；</p><p>2．依法向人民法院起诉。</p><h2>第二十五条  双方确定：本合同及相关附件中所涉及的有关名词</h2><p>和技术术语，其定义和解译如下：</p><p>1．</p><p>2．</p><h2>第二十六条  与履行本合同有关的下列技术文件，经双方以  商</h2><p>定   方式确认后，为本合同的组成部分：</p><p>1．技术背景资料：    ；</p><p>2．可行性论证报告：       ；</p><p>3．技术评价报告：     ；</p><p>4．技术标准和规范：               ；</p><p>5．原始设计和工艺文件：                  ；</p><p>6．其他：</p><h2>第二十七条  双方约定本合同其他相关事项为：      。</h2><h2>第二十八条  本合同一式  贰    份，具有同等法律效力。</h2><h2>第二十九条  本合同经双方签字盖章后生效。</h2><p>甲方：                     （盖章）</p><p>法定代表人/委托代理人：                           （签名）</p><p>年       月       日</p><p>乙方：                      （盖章）</p><p>法定代表人/委托代理人：                  （签名）</p><p>年       月       日</p>',NULL,11,'2026-06-03 20:33:30','2026-06-03 20:33:31',0),(11,NULL,30,'SUCCESS','<h1>技术转让合同</h1><p>受让人：_________以下简称甲方)	让与人：__________(以下简称乙方)</p><p>地址：________________________	地址：_______________________</p><p>电话：_________________________	电话：________________________</p><p>开户银行：______________________	开户银行：____________________</p><p>账号：__________________________	账号：________________________</p><p>鉴于乙方持有设计、制造、安装以及销售的技术秘密，并有权向甲方许可上述技术秘密，甲方愿意利用上述技术秘密设计、制造、安装并销售合同产品，但不单售零部件。双方通过充分协商达成如下协议：</p><p>定义</p><p>1.1除非本合同中下文另有明确规定的含义，用于本合同的下列术语定义的：</p><p>A.技术秘密：指设计、制造、安装及销售合同产品所需的一切技术知识和经验，以及一切与之相关的秘密技术资料和实际技巧，包括已申请专利部分和未申请专利部分的一切所需资料。</p><p>B.合同产品：指甲方根据乙方的技术秘密设计、制造的产品。</p><p>详见本合同附件一。</p><p>C.考核产品：指甲方根据乙方许可的技术所设计、制造的产品本合同附件五的规定进行考核验收的各型号的第一批中的任一合同产品。</p><p>D.技术资料：指附件二中所列乙方用于设计、制造、安装、维修和销售合同产品技术资料、图纸、技术数据以及2方现有的一切有关的其他资料。</p><p>E.补充技术：指本合同有效期内由乙方进一步开发的与设计、制造、安装及维修合同产品有关的技术。</p><p>F.改进技术：指在本合同有效期内由甲方开发的，对本合同产品的设计、制造、安装和维修技术作出的改进。</p><p>G.净销售额：指从合同产品的总销售价中扣除运输费、包装费、保管费和保险费后所剩的金额数。</p><p>合同的种类、内容和范围</p><p>2.1本合同为普通许可。甲方无权将该技术秘密透露或许可给任何第三方。</p><p>2.2乙方同意甲方享有在工厂设计、制造合同产品的权利及在除港、澳、台之外的中国境内使用、维修和销售合同产品的权利。销售权不包括单售零部件。</p><p>2.3甲方承担义务不向国外及港、澳、台出售合同产品及零部件，如有违约，则应承担由此而产生的一切法律和经济责任。</p><p>2.4乙方有责任向甲方提供所有有关的技术秘密资料，其具体内容和交付时间详见本合同附件二。</p><p>2.5乙方有责任对甲方的技术人员进行培训和技术指导，使甲方技术人员尽快掌握上述技术，具体要求详见本合同附件三。</p><p>2.6乙方将派遣技术人员赴甲方工厂进行技术服务，具体要求详见本合同附件四。</p><p>2.7乙方授予甲方使用乙方商标的权利，合同产品的商标如下：_________________</p><p>费用</p><p>3.1入门费：甲方须向乙方支付入门费_______元。该入门费包括资料交付前的费用及甲方应向乙方支付的各种技术服务和培训费。</p><p>3.2提成费：从本合同生效之日起三年内，甲方每销售一台合同产品，乙方从中提取使用费_______元。</p><p>3.3从本合同生效之日起三年内，甲方向乙方支付使用费的计算方法为：第一年最低提成合同产品的数量为_______台;第二年最低提成合同产品的数量为_______台;第三年最低提成合同产品的数量为_______台。</p><p>3.4从本合同生效之日起满三年后的第四个年度算起，甲方向乙方支付每台合同产品净销售额的_______%作为使用费。</p><p>支付条件和支付方式</p><p>4.1甲方向乙方支付本合同规定的一切费用，均以人民币转帐支付。</p><p>4.2入门费_______元按下列方式和比例由甲方支付给乙方。</p><p>A.合同生效后7日由甲方将入门费的20%即_______元支付给乙方。</p><p>B.甲方收到乙方提供的附件二中所规定的第一批技术资后3日内，将入门费的50%即_______元支付给乙方。</p><p>C.甲方收到乙方提供的附件二中所规定的最后一批技术资料后3日内，支付入门费中其余30%即_______元。</p><p>4.3根据本合同第七条第二款规定，考核产品验收后，从合同生效之日起3年内，甲方按以下要求支付使用费。</p><p>A.每年12月31日后的15天内，甲方将上一年度合同产品的实际销售量和销售价通知乙方。</p><p>B.甲方在收到乙方的单据后15天之内向乙方支付使用</p><p>4.4在合同生效满3年后，第四年度开始，按下列要求支付使用费。</p><p>A.在每一年度最后一日后的15天内，甲方将上一年度合同产品的实际销售量和销售价通知乙方。</p><p>B.甲方在收到乙方对销售量和销售价的确认书以及该年度使用费计算书后15天内，向乙方支付使用费。</p><p>技术资料的交付</p><p>5.1乙方应按本合同附件二规定的技术资料交付时间和内容，通过邮局将资料挂号寄给甲方。</p><p>5.2甲方所在地所属邮局的落地印戳日期为技术资料的实际交付日期。甲方在收到资料后7天内须将收到单据复印件寄给乙方。</p><p>5.3乙方在技术资料寄出后48小时之后，须将合同号、寄出资料的挂号单复印件、资料目录清单、件数用挂号信通知甲方。</p><p>5.4如技术资料在邮寄中有丢失、损坏、短缺等现象，乙方应在收到甲方的书面通知后15天内，再次免费补寄给甲方。</p><p>5.5每包(箱)技术资料的包装封面上应写明：</p><p>A.合同号：</p><p>B.收货人：</p><p>C.目的地：</p><p>D.件号、箱号：</p><p>5.6技术资料包(箱)内须附详细的技术资料清单二份，标明序号、文件代号、名称和号码。</p><p>技术资料的修改和改进</p><p>6.1乙方提供的技术资料，如有不适合甲方实际生产条件时，在不影响合同产品性能的原则下，乙方有义务协助甲方修改技术资料，并加以确认。</p><p>6.2在本合同有效期内，双方对合同产品的任何改进和发展，都有义务及时通知对方，免费把改进和发展的技术资料提交给对方，并向对方提供改进发展技术的处理意见，但其所有权属于提供技术的一方。</p><p>6.3未经乙方确认的技术资料，甲方保证不先实施于合同产品。</p><p>6.4在本合同有效期内，凡属甲乙双方共同进行合作研究所产生的改进和发展技术，其所有权归双方共有。</p><p>6.5甲乙双方对双方所取得的任何改进和发展技术，都享有优先使用权，所有方应提供各种帮助，使对方顺利实施其改进和发展技术，但如果没有得到所有方的同意，另一方不得擅自向任何第三者泄露改进和发展技术。</p><p>考核与验收</p><p>7.1为验证乙方在技术资料的正确性、可靠性和考核甲方生产合同产品的能力，由甲方和乙方技术人员共同在甲方工厂对合同产品进行考核验收，具体办法详见合同附件五。</p><p>7.2经考核，合同产品的技术参数和性能如符合乙方提出的要求，双方应共同签署合同产品考核验收合格证书一式二份，双方各执一份。</p><p>7.3如考核产品的技术性能达不到合同规定的技术指标，双方应友好协商，共同研究分析原因，采取措施，消除缺陷后进行第二次性能考核。考核合格按7.2条规定双方签署合格证书。</p><p>7.4第二次考核仍不合格，如系乙方责任，例如提供技术资料培训、技术服务不正确等原因，乙方应承担第二次考核的全部费用并且自费派人参加第三次考核，如系甲方责任，则由甲方承担第二次考核的全部费用，并承担乙方技术人员参加第三次考核的全部费用。</p><p>7.5第三次考核合格，合同产品按7.5条规定签署合格证书，仍不合格，则双方应协商研究本合同进一步执行的具体问题。</p><p>保证和索赔</p><p>8.1乙方保证所提供的技术资料是乙方实际使用的最新的、完整的、正确的技术资料，并保证按时提供。</p><p>8.2乙方保证在本合同有效期内及时免费向甲方提供任何改进和发展技术资料。</p><p>8.3乙方如果迟交技术资料超过6个月，甲方有权终止合同。</p><p>8.4甲方保证在本合同有效期内充分实施该技术秘密，并严格按照乙方提供的技术资料和技术指导操作。</p><p>8.5甲方保证对在本合同有效期内所实行的任何改进和发展技术，都将免费及时地提供给乙方。</p><p>8.6甲方保证按照本合同第四条和第五条的规定，按时支付使用费。如超过规定的期限，则应在规定期满后的15天内补交使用费并加10%的利息。</p><p>8.7甲方保证，未经乙方同意，不将乙方提供的任何图纸和技术资料用于实施本合同之外的其他目的。</p><p>侵权和保密</p><p>9.1乙方保证是合同所述技术秘密和技术资料的合法所有者，并有权向甲方转让，如果发生第三方指控，乙方负责与第三方交涉并承担法律上和经济上的全部责任。如果第三方直接指控甲方，甲方应立即通知乙方，仍由乙方出面交涉并承担法律上和经济上的全部责任。</p><p>9.2甲方同意在本合同有效期内，对乙方向甲方提供的技术秘密与之相关的一切技术资料、图纸予以保密。未经乙方同意，不得将上述技术秘密及有关资料泄密。未经乙方同意，不得将上述技术秘密及有关资料泄密给任何第三方。同时还保证采取措施防止任何泄露情况发生。</p><p>9.3如果甲方发生泄密情况，乙方有权根据泄密的范围和程度要求对方赔偿损失。</p><p>9.4如果上述技术秘密的部分或全部由乙方或第三方公开，则甲方对已公开部分将不再承担保密义务。</p><p>争议的解决</p><p>因执行本合同所发生的或与本合同有关的一切争议，均应由双方通过友好协商解决。协商不成的，报请专利局(处)调处，调处费由双方均摊。</p><p>调处不成的，任何一方均可向人民法院起诉，诉讼费由败诉方负担。</p><p>除了进行调处或诉讼的部分外，本合同的其余部分应继续执行。</p><p>不可抗力</p><p>在本合同有效期内，签约双方中的任何一方由于战争、严重水灾、火灾、台风和地震及其他双方同意的不可抗力事故而影响合同执行时，则延长履行合同的期限，延长期相当于事故所影响的时间。</p><p>遭遇不可抗力的一方应于事故发生之日起5天内，用电报或信件通知对方，并于15天内将有关部门出具的关于该事故的证明文件用挂号信提交对方确认。</p><p>任何一方都无权以上述事故为理由终止合同，也无权向另一方提出因此而不能履行或不能完全履行或推迟履行的损失赔偿费要求。</p><p>如不可抗力事故延续到120天以上时，双方应在事故解除之日起15天内通过友好协商解决继续执行合同的问题，逾期不能达成协议，本合同自动解除。</p><p>合同的生效、终止及其他</p><p>本合同由双方代表签字、盖章后生效。</p><p>本合同有效期从生效之日算起为_______年。有效期满后，本合同自动失效。</p><p>根据双方中任何一方提议，本合同可按双方满意的条件延期，并在本合同期满前6个月进行商谈。</p><p>在本合同有效期内，甲方会计人员对合同产品的销售情况要单立账簿，在每台(批)合同产品的销售单据上，应对1.10款中所列的各项支出分别列项。对没有分别列项或项目不全的单据，将被视为已经扣除上述各项支出计算的单据。</p><p>本合同期满时，双方发生的未了债权和债务，不受本合同期满的影响。债务人应向债权人继续偿付未了债务。</p><p>本合同期满之日前甲方已经完成制造或接近完成制造的合同产品，应视为已销售的合同产品，并按规定支付使用费。</p><p>本合同附件一至六为本合同不可分割的组成部分，与本合同正文具有同等效力。</p><p>对本合同各条款及附件的任何变更、修改和增减，须经双方友好协商，由授权代表签署书面文件，作为本合同的组成部分，具有同等效力。</p><p>甲方：(签章)_______________	乙方：(签章)_______________</p><p>代表人：(签字)_____________	代表人：(签字)_____________</p>',NULL,1,'2026-06-03 20:33:50','2026-06-03 20:33:51',0),(12,NULL,39,'SUCCESS','<h1>合同编号：</h1><p>系统维保合同书</p><p>甲方：</p><p>法定代表人/负责人：</p><p>证件类型：□统一社会信用代码 □个体工商户注册号 □身份证号码</p><p>证件号码：\n联系人：             联系电话：                电子邮箱：\n地址：\n　　\n乙方：</p><p>法定代表人/负责人：\n证件类型：□统一社会信用代码 □个体工商户注册号 □身份证号码</p><p>证件号码：\n联系人：             联系电话：                电子邮箱：\n住址：</p><p>根据中华人民共和国有关法律的规定，本着平等互利的原则，为明确甲乙双方的权利和义务，确保等科技设备的正常运行，经双方友好协商，达成如下协议：</p><h3>一、维保范围</h3><p>乙方为甲方的所有接入系统的所有硬件、软件提供运行维保服务。范围是（详见附件1）：</p><p>1、电视监控系统；</p><p>2、电子警察系统；</p><p>3、交通治安卡口系统（包括自建卡口、整合卡口、社会资源卡口）；</p><p>4、承建的所有联网信号机系统；</p><p>5、电子诱导屏系统；</p><p>6、网上督察系统；</p><p>7、监控中心系统；</p><p>8、指挥中心设备及软件系统等；</p><p>9、的所有的接入系统；</p><p>10、相关业务；</p><p>11、每年签订新合同以前，对于其它需要纳入维保范围的系统不再另行收费。</p><h3>二、维保内容</h3><p>维修内容主要分为故障检修、应急抢修和日常维护保养三部分（详见附件2），具体内容如下：</p><p>1、前端设备（枪机、球机、光源、雷达等）的日常维保巡检、应急抢修，每月清理一次；</p><p>2 、后端设施（交换机、服务器、数据库存储阵列等）的日常维保、巡检、应急抢修和机房保洁；</p><p>3 、应用软件（非现场数据、所有卡口数据、所有电警数据、所有人工抓拍数据、所有监控资料等）的日常维保；</p><p>4 、监控中心运行保障。</p><p>5 、重大活动及事件应急保障。</p><p>6 、新建前端及系统的联网接入及应用，包括产品更换升级；</p><p>7 、免费进行中心平台和前端设备及各大队设备、软件的升级，并对甲方要求的功能进行完善；</p><p>8 、加强平台数据库维护管理，随时做好移交工作；</p><p>9 、乙方承建和整合的所有系统及软硬件均在维保范围内。（整合入甲方平台系统的维修分界线是甲方与被整合方对接平台运行服务器）</p><h3>三、维保方式</h3><p>1 、乙方派驻1名维保人员常驻  ,2名维保人员常驻（派驻大队维保人员管理制度，详见附件3）；</p><p>2 、维保采用派工单制度，由支队、大队根据故障情况以书面形式通知维保人员，维保人员在维护过程中发现故障时应主动维修，但维修前必须报支队、大队科技人员批准，事后补签手续；</p><p>3 、支队派工单由科技科分管责任人和科技科负责人签字确认，大队派工单由科技人员和大队分管领导签字确认；</p><p>4 、遇有重特大事件时，乙方要启动抢修预案积极应对（重特大事件及意外突发状况应急预案，详见附件4）</p><p>5、设备损坏时优先维修，无法修复时进行更换。</p><h3>四、维保费用及支付方法</h3><p>1 、经双方协商，为保障乙方系统维护工作的正常进行，确保甲方系统始终处于良好工作状态。维保费用大包干形式，维保范围内每年维保费用为圆整（￥元）。</p><p>2 、本合同生效后，甲方在每月下旬支付给乙方上月的维保费，为方便支付，第1个支付月份到第11个月份每月支付整（￥元），第12个支付月份支付元整（￥元）。</p><p>3、每年签订新合同前，对于需要纳入维保范围的新系统，不再另行收费，对于低值易损品或无维修价值设备，如电源、空开、插座等故障单点每处每次有元的减免；</p><p>4 、维保人员在维保过程中，需要更换的主要设备（智能球机、采集单元、补光灯、服务器、光端机等）由甲方购买。由大队提出需求，支队审批购买，损坏的设备由大队登记保存；</p><p>5 、超出本合同约定的维保范围的，由乙方出具维保费用清单，各区县大队负责人签字，经支队审批后，方可实施维修。</p><p>6 、对因不可抗拒力及交通事故等原因所发生的维护、更换设备费用双方协商处理。</p><p>7 、甲方对乙方实行满意度评分，满意率达不到 %，整改满意后付款,满意率达不到 %，扣除当月维保费的  %，满意率达不到 %，扣除当月全部维保费用，满意率达不到 %，甲方有权解除合同，并向乙方追偿因此而造成的直接和间接经济损失。（详见附件5）。</p><h3>五、双方的义务</h3><p>1、甲方的义务</p><p>1）甲方必须按本合同约定按期支付给乙方相应款项，本合同中涉及的所有软硬件产权均归属甲方所有，由此产生的知识产权全部归属甲方，乙方使用成果须征得甲方同意；</p><p>2）甲方应对乙方工作的顺利开展提供便利条件，并指派专人负责。乙方的定期维护、保养计划要报甲方批准、备案。对于乙方的日常维保工作，甲方发现问题，立即通知乙方整改。</p><p>2 、乙方的义务</p><p>1）乙方要做好系统设备的维保工作，负责对各系统的日常监测，保障各系统长期有效地运行（见附件二）；</p><p>2）乙方必须配备检修、保养工作所用的交通工具，升降设备、监测设备、仪器仪表，对系统所需的常用配件须常年备货；</p><p>3）乙方必须建立一支有相关专业知识组成的专业技术队伍， (详见附件6)，提供服务。</p><p>4）乙方必须向甲方提供详细的工作计划与安排，对每次检修、保养工作做好记录，以接受甲方的监督与检查。</p><p>5）每月月底提交   个大队、车管所、监考科、网上督察、智能交通综合管控平台系统的运行情况，需包含以下十个指标（详见附件7）</p><p>A、各系统设备有效运行率，B、各系统设备完好率，C、各系统设备维修率、D、规定时间内维修完好百分比，E、系统综合评价，F、用户满意度。</p><p>本合同一经签署即具有法律效力，任何一方违约均须赔偿对方的损失。</p><p>甲方延期支付将按延期款总额以每日千分之三支付违约金。</p><p>乙方维修不及时，发生故障不在规定时间内修复（非乙方过错除外），每发生一次，按当月维修金额的百分之三支付违约金。</p><p>因本合同引起的或与本合同有关的任何争议，双方可协商解决，协商不成，按如下第    种方式处理：（1）向有管辖权的       人民法院提起诉讼；（2）向        仲裁委员会申请仲裁。</p><p>其他</p><p>1、本合同有效期限      年，自    年   月   日至     年  月   日止，合同期满后，双方均未书面提出终止本合同，则本合同有效期自动顺廷      年。</p><p>2、本合同一式两份，甲乙双方各执壹份、具有同等法律效力。</p><p>3、本合同以双方签字、单位盖章后生效。</p><p>甲方（盖章）：                       乙方（盖章）：</p><p>代表人（签名）：                     代表人（签名）：</p><p>年  月  日                          年   月    日</p>',NULL,1,'2026-06-03 20:47:12','2026-06-03 20:47:13',0);

